// --- ANIMATION HELPER ---
const AnimateEntry = ({ 
    children, 
    animation, 
    delay = 0, 
    className = '', 
    style = {} 
}: { 
    children: React.ReactNode; 
    animation: 'fade-up' | 'fade-down' | 'fade-left' | 'fade-right' | 'zoom-in' | 'zoom-out' | 'fade-in'; 
    delay?: number; 
    className?: string; 
    style?: React.CSSProperties; 
}) => {
    const [visible, setVisible] = useState(false);
    useEffect(() => {
        const timer = setTimeout(() => setVisible(true), delay);
        return () => clearTimeout(timer);
    }, [delay]);

    const getBaseTransform = () => {
        switch(animation) {
            case 'fade-up': return 'translateY(20px)';
            case 'fade-down': return 'translateY(-20px)';
            case 'fade-left': return 'translateX(20px)';
            case 'fade-right': return 'translateX(-20px)';
            case 'zoom-in': return 'scale(0.9)';
            case 'zoom-out': return 'scale(1.1)';
            default: return '';
        }
    };

    const transitionClass = visible 
        ? 'opacity-100 transform-none' 
        : `opacity-0 ${getBaseTransform()}`;

    return (
        <div 
            className={`transition-all duration-500 ease-out ${transitionClass} ${className}`}
            style={style}
        >
            {children}
        </div>
    );
};

